mapper.select:
SELECT id, name, id_card_no, passenger_type, phone
FROM passenger WHERE user_id = #{userId}
ORDER BY created_at DESC

mapper.update:
UPDATE passenger
SET name = #{name}, id_card_no = #{idCardNo}, passenger_type = #{passengerType}, phone = #{phone}
WHERE id = #{id}

mapper.select:
SELECT COUNT(*) > 0 FROM passenger
WHERE user_id = #{userId} AND id_card_no = #{idCardNo}

    AND id != #{excludeId}
